mapper.select:
select * from nx_customer_promotion_campaign

    and community_id = #{communityId}
    and commerce_id = #{commerceId}
    and owner_scope = #{ownerScope}
    and campaign_status = #{campaignStatus}
    and campaign_scene = #{campaignScene}
    and campaign_code = #{campaignCode}

order by created_at desc
limit #{offset}, #{limit}

select * from nx_customer_promotion_campaign
where community_id = #{communityId}
  and commerce_id = #{commerceId}
  and campaign_scene = #{campaignScene}
  and campaign_status = 'ACTIVE'
  and (owner_scope = #{ownerScope} or owner_scope = 'ALL')
  and (effective_start_at is null or effective_start_at <= #{now})
  and (effective_end_at is null or effective_end_at >= #{now})
order by nx_customer_promotion_campaign_id asc

select count(*) from nx_customer_promotion_campaign
where community_id = #{communityId}
  and commerce_id = #{commerceId}
  and campaign_scene = #{campaignScene}
  and campaign_status != 'TERMINATED'
  and (
    owner_scope = #{ownerScope}
    or owner_scope = 'ALL'
    or #{ownerScope} = 'ALL'
  )

      and nx_customer_promotion_campaign_id != #{excludeCampaignId}

  and (
    (effective_start_at is null and effective_end_at is null)
    or (#{effectiveStartAt} is null and #{effectiveEndAt} is null)
    or (
      (effective_start_at is null or effective_start_at <= IFNULL(#{effectiveEndAt}, '9999-12-31 23:59:59'))
      and (effective_end_at is null or effective_end_at >= IFNULL(#{effectiveStartAt}, '1970-01-01 00:00:00'))
    )
  )

select count(*) from nx_customer_user_referral
where campaign_id = #{value}
  and qualification_status = 'QUALIFIED'

mapper.update:
update nx_customer_promotion_campaign
campaign_name = #{campaignName}, campaign_status = #{campaignStatus}, effective_start_at = #{effectiveStartAt}, effective_end_at = #{effectiveEndAt}, terminated_at = #{terminatedAt}, status_reason = #{statusReason}, campaign_version = #{campaignVersion},
where nx_customer_promotion_campaign_id = #{nxCustomerPromotionCampaignId}
